# words 326-400
B7 = {
326: {"nativeDefinition": "To go out onto the streets; to be released publicly.", "japaneseMeaning": "街に出る、（製品が）発売される", "etymology": "hit the streets（街を歩く）の直訳的表現。", "examples": {"B": "今日はニューヨークの街に出て、住むことの長所短所を人に聞く。", "C": "この新製品が発売されるのが待ち遠しい。", "D": "通りを歩く。発売される。"}},
327: {"nativeDefinition": "To present or consider something in a particular way.", "japaneseMeaning": "（何かを）〜という枠組みで捉える、位置づける", "etymology": "frame（枠に入れる）の比喩的用法。", "examples": {"B": "どう捉えるか次第で、ギリギリ合格は運が良かったとも、ちょうどいい勉強量だったとも言える。", "C": "人種差別はあると思うけど、すべての問題を人種問題として枠づけるのはナンセンス。", "D": "何かを考慮する。"}},
328: {"nativeDefinition": "To look at someone intensely; to estimate by sight.", "japaneseMeaning": "（人を）じろじろ見る、（目測で）見積もる", "etymology": "eyeball（眼球）の動詞用法。", "examples": {"B": "向かいの男がじろじろ見てきて気持ち悪い。", "C": "レシピがなかったから目測で調味料入れたけど、ほぼ完璧だった。", "D": "じっと見る。目測する。"}},
329: {"nativeDefinition": "A moment of sudden realization or inspiration.", "japaneseMeaning": "ひらめき、電球が点灯した瞬間", "etymology": "light-bulb moment（電球の瞬間）の比喩的表現。", "examples": {"B": "シャワー中にひらめいたんだけど、もう何だったか忘れた。", "C": "ワークショップ中にひらめいて、自分の情熱はロボティクスとプログラミングだとわかった。", "D": "突然の気づきやインスピレーションの瞬間。"}},
330: {"nativeDefinition": "Areas of ambiguity rather than clear right and wrong.", "japaneseMeaning": "グレーゾーン、曖昧さ", "etymology": "shades of gray（灰色の色合い）が白黒はっきりしない領域を指す。", "examples": {"B": "言語は常に論理的じゃない。グレーゾーンがあることを受け入れないと、ずっとイライラする。", "C": "人生は白か黒かじゃなく、グレーゾーン。だからみんなたどたどり歩いてる。", "D": "曖昧さ。"}},
331: {"nativeDefinition": "To suggest an idea to someone for feedback.", "japaneseMeaning": "（アイデアを）さりげなく提案する、相談する", "etymology": "float an idea（アイデアを浮かべる）の比喩。", "examples": {"B": "このアイデアを提案してくれたのはフィオナだから、俺の手柄じゃない。", "C": "ちょっといい？アイデアを一つ相談させて。", "D": "誰かにアイデアを提案する。"}},
332: {"nativeDefinition": "Something with both positive and negative consequences.", "japaneseMeaning": "諸刃の剣、両刃の剣", "etymology": "double-edged sword（両刃の剣）の直訳的慣用表現。", "examples": {"B": "自分の意見をはっきり言うべきだと思うけど、嫌われるかも。諸刃の剣だよね。", "C": "インターネットは諸刃の剣。夢を叶えるチャンスもあるけど、競争も激化してる。", "D": "プラスとマイナスの両面があるもの。"}},
333: {"nativeDefinition": "The situation is unfairly unfavorable to someone.", "japaneseMeaning": "不利な状況、勝負が決まってる", "etymology": "the deck is stacked against（山札が不利に積まれている）の比喩。", "examples": {"B": "要するに、山札が不利に積まれてる。どれだけ頑張っても今年は昇進しない。", "C": "大学行かないと就職で不利だけど、不可能じゃない。君は君のやり方で。", "D": "誰かにとって状況が不利。"}},
334: {"nativeDefinition": "To understand the hidden or implied meaning.", "japaneseMeaning": "行間を読む、真意を理解する", "etymology": "read between the lines（行と行の間を読む）の慣用表現。", "examples": {"B": "ビジネス交渉では相手の手の内を見せないから、行間を読む能力が重要。", "C": "冗談で言ったのに文字通り受け取って怒られた。もっと行間を読んでほしい。", "D": "隠れたメッセージを理解する。"}},
335: {"nativeDefinition": "To end someone's suffering; to put someone out of their misery.", "japaneseMeaning": "（人を）苦しみから解放する、早く結果を教えて", "etymology": "put out of one's misery（苦しみから出す）の直訳的表現。", "examples": {"B": "安楽死は議論の的だけど、余命ない犬には選択肢としてあるべきだと思う。", "C": "結果は来月まで出ないの？もう早く教えてよ。", "D": "誰かを苦しみから解放する。"}},
336: {"nativeDefinition": "A situation that repeats monotonously like the movie Groundhog Day.", "japaneseMeaning": "グラウンドホッグデー状態、同じことの繰り返し", "etymology": "映画『グラウンドホッグ・デー』（同じ日が繰り返される）から。", "examples": {"B": "最近やってることは仕事、食事、睡眠の繰り返し。グラウンドホッグデーみたい。", "C": "この動画見るたびグラウンドホッグデー感。同じ内容を違う切り口で何度も。", "D": "同じ日が繰り返される。"}},
337: {"nativeDefinition": "Frozen in fear or confusion like a deer facing headlights.", "japaneseMeaning": "（恐怖で）固まる、ヘッドライトを見る鹿のように", "etymology": "deer in the headlights（ヘッドライトを見る鹿）の直訳的比喩。", "examples": {"B": "面接官が急に難しい質問をして、頭が真っ白。ヘッドライトを見る鹿みたいだった。", "C": "プレゼン中にオーと言及したとき、キャシーが固まってた。", "D": "恐怖で凍りつく。"}},
338: {"nativeDefinition": "A fundamental component or basis of something.", "japaneseMeaning": "構成要素、基本ブロック", "etymology": "building block（積み木）の比喩的用法。", "examples": {"B": "自信の重要な構成要素の一つは、多くの成功体験を積むこと。", "C": "成功の鍵となる構成要素は、戦略的思考と何があっても前進する力。", "D": "基本的な構成要素。"}},
339: {"nativeDefinition": "To punish someone as a warning to others.", "japaneseMeaning": "（人を）見せしめにする、懲らしめる", "etymology": "make an example of（例にする）の慣用表現。", "examples": {"B": "マネージャー、今日はきつかった。みんなの前で俺を見せしめにした。", "C": "去年逮捕されたけど、有力な証拠はなかった。検察は見せしめにしたかったんだと思う。", "D": "他の人に警告するために罰する。"}},
340: {"nativeDefinition": "To remain successful or popular over a long period.", "japaneseMeaning": "時代に耐える、長く愛される", "etymology": "stand the test of time（時の試練に耐える）の慣用表現。", "examples": {"B": "スタン・スミスは時代に耐えるアディダスの定番スニーカー。", "C": "マイケル・ジャクソンの音楽が長く愛され続けてるのはすごい。", "D": "長い間成功し続ける。"}},
341: {"nativeDefinition": "The more people involved, the better and more fun.", "japaneseMeaning": "多ければ多いほど楽しい、大勢の方が盛り上がる", "etymology": "the more the merrier（多いほど陽気）の直訳的慣用表現。", "examples": {"B": "友達も連れてきて。多ければ多いほど楽しいから。", "C": "人が多すぎるって？まあ、多ければ多いほど楽しいかな。", "D": "人が多いほど楽しい。"}},
342: {"nativeDefinition": "An unfair campaign to blame or punish someone.", "japaneseMeaning": "魔女狩り、不当な糾弾", "etymology": "witch hunt（魔女狩り）の歴史的比喩。", "examples": {"B": "SNSの魔女狩り、人類の未来が心配になる。", "C": "香港での中国政府の行動は、愛国心が足りない人への魔女狩りだと思う。", "D": "不当で非合理的な非難。"}},
343: {"nativeDefinition": "A person considered flawed or no longer valuable.", "japaneseMeaning": "傷物、使い物にならない人", "etymology": "damaged goods（傷ついた商品）が人にも使われる。", "examples": {"B": "4週間もプロジェクトにアサインされない。傷物扱いされてるのかな。", "C": "成長し続けない人は、この厳しい職場ではすぐ傷物になる。", "D": "望まれない不適切な人。"}},
344: {"nativeDefinition": "To deliberately provoke someone to anger.", "japaneseMeaning": "（人を）わざと怒らせる、カチンとさせる", "etymology": "get a rise out of（反応を引き出す）の口語表現。", "examples": {"B": "明らかに挑発してる。わざと怒らせようとしてるだけ。ブロックする。", "C": "ごめん、冗談だった。怒らせようとしたわけじゃない。", "D": "意図的に怒らせる。"}},
345: {"nativeDefinition": "Be honest; let's be real.", "japaneseMeaning": "正直に言うと、本音を言えば", "etymology": "be real（本物であれ）の口語的用法。", "examples": {"B": "正直に言うと、俺はお酒が嫌いなんだけど、みんなが飲むから飲んでる。", "C": "本音を言えば、事実と意見を区別できない人が多い。だからフェイクニュースが広がる。", "D": "正直である。"}},
346: {"nativeDefinition": "Just in time; at the last possible moment.", "japaneseMeaning": "間一髪、ギリギリ間に合って", "etymology": "in the nick of time（時の切れ目に）の慣用表現。", "examples": {"B": "閉店数分前にギリギリ間に合った。", "C": "空港にギリギリ間に合った。よかった。", "D": "ぎりぎり間に合って。"}},
347: {"nativeDefinition": "To have an unresolved grievance with someone.", "japaneseMeaning": "（人に）恨みがある、決着をつけたい", "etymology": "have a score to settle（決着をつける点数がある）の表現。", "examples": {"B": "決勝でジョーカーに決着をつけたかった。そしてつけた。", "C": "なんであの写真みんなに送ったの？俺に恨みでもあるの？", "D": "誰かに復讐したい。"}},
348: {"nativeDefinition": "Not knowing or understanding something.", "japaneseMeaning": "まったくわからない、何が言ってるか不明", "etymology": "none the wiser（賢くならない）の慣用表現。", "examples": {"B": "AIはパンドラの箱を開けたけど、多くの人はまだわかってない。いつか世界を支配する。", "C": "妹と友達の会話を30分聞いてるけど、何の話かまったくわからない。", "D": "理解していない。"}},
349: {"nativeDefinition": "In a similar style or manner.", "japaneseMeaning": "同じ路線で、同様に", "etymology": "in the same vein（同じ血管で）の比喩的表現。", "examples": {"B": "『猫の恩返し』は他のジブリ作品とは違う路線だけど、楽しい映画。", "C": "子供の頃コミック収集が好きだったし、同様にアニメにもハマってた。", "D": "似ている。同様に。"}},
350: {"nativeDefinition": "In a situation too difficult to handle.", "japaneseMeaning": "手に負えない、能力を超えている", "etymology": "in over one's head（頭の上にいる）で、対処できないことを表す。", "examples": {"B": "2週間でマラソン完走できると思ったけど、明らかに手に負えない。", "C": "新しい仕事は好調にスタートしたけど、今は手に負えない。何やってるかわからない。", "D": "能力を超えている。"}},
351: {"nativeDefinition": "When one thing happens, many similar things follow.", "japaneseMeaning": "泣きっ面に蜂、禍不单行", "etymology": "when it rains, it pours（雨が降れば土砂降り）のことわざ。", "examples": {"B": "エアコン壊れた、冷蔵庫の電気消えた、車も動かない。泣きっ面に蜂だ。", "C": "昇給、新しい彼女、来週休暇。いいことも悪いこともまとめて来る。", "D": "良いことも悪いこともまとめて起きる。"}},
352: {"nativeDefinition": "An unexpected twist or surprise.", "japaneseMeaning": "どんでん返し、プロットツイスト", "etymology": "plot twist（プロットのねじれ）の物語用語。", "examples": {"B": "宇宙人信じる？どんでん返し、俺は宇宙人だ。", "C": "明日2つの課題提出。どんでん返し、まだ手をつけてない。", "D": "驚き！"}},
353: {"nativeDefinition": "To be the most extreme example (best or worst).", "japaneseMeaning": "最高に〜だ、最たる〜", "etymology": "take the cake（ケーキを取る）の古い慣用表現。", "examples": {"B": "ビルはいろいろ変な決断してきたけど、ヘビをペットにするのは最たるものだ。", "C": "ケンのタトゥーは最高。見たことある中でピカチュウが背中にあるのはすごい。", "D": "最悪だ。最高だ。"}},
354: {"nativeDefinition": "Finally mentioned but equally important.", "japaneseMeaning": "最後だが同様に重要な", "etymology": "last but not least（最後だが最も少なくない）の定型表現。", "examples": {"B": "最後に、本日のファシリテーター、ダグラス・カペル氏を紹介します。", "C": "最後に、今日はご参加ありがとうございました。次回お会いしましょう。お気をつけて！", "D": "最後だが同様に重要。"}},
355: {"nativeDefinition": "A highly competitive environment where people harm each other.", "japaneseMeaning": "弱肉強食、犬同士の世界", "etymology": "dog-eat-dog（犬が犬を食う）の直訳的慣用表現。", "examples": {"B": "ビジネスは弱肉強食。誰も信用できない。", "C": "弱肉強食だけど、俺はアダムなら何があっても味方してくれると思う。長年の親友だから。", "D": "高度に競争的な環境。"}},
356: {"nativeDefinition": "Be quiet! (informal and rude).", "japaneseMeaning": "黙れ、うるさい", "etymology": "put a sock in it（靴下を入れろ）の古い口語表現。", "examples": {"B": "フレッド、黙ってくれ。ずっと自慢話してる。", "C": "彼女に黙らせてくれない？甲高い声で耳が痛い。", "D": "静かにしろ。"}},
357: {"nativeDefinition": "Money has great influence and power.", "japaneseMeaning": "金の力は偉大、金が物を言う", "etymology": "money talks（金が話す）の直訳的慣用表現。", "examples": {"B": "ジョシュの転職、まだ悲しいの？もう済んだこと。金が物を言う。", "C": "このアプリ、広告が増える前はずっと良かった。悲しいけど、金が物を言う。", "D": "金は巨大な影響力を持つ。"}},
358: {"nativeDefinition": "The process has already begun and cannot be stopped.", "japaneseMeaning": "すでに動き出している、歯車は回り始めた", "etymology": "wheels in motion（動いている車輪）の比喩。", "examples": {"B": "本気だよ、次の選挙で大統領に立候補する。もう動き出してる。", "C": "ヘレンは歯車が回り始めてからでないと計画を言わない。", "D": "プロセスはすでに始まっている。"}},
359: {"nativeDefinition": "To take the morally superior path.", "japaneseMeaning": "高潔な道を選ぶ、道徳的に正しい行動をする", "etymology": "take the high road（高い道を取る）の比喩。", "examples": {"B": "父はどんなに困難でも高潔な道を選ぶよう教えてくれた。強い道徳観の形成に役立った。", "C": "ヘイトはある。無視して、いつも高潔な道を選んで。", "D": "道徳的に強い行動をする。"}},
360: {"nativeDefinition": "To sell very quickly and in large quantities.", "japaneseMeaning": "飛ぶように売れる、大売れする", "etymology": "sell like hotcakes（ホットケーキのように売れる）の慣用表現。", "examples": {"B": "俺の顔がプリントされたティッシュ、面白いし絶対大売れする。", "C": "まだお客が少しずつ来てるけど、まだ早い時間。でもこのピンズは大売れすると思う。可愛いし。", "D": "速く大量に売れる。"}},
361: {"nativeDefinition": "To reveal a lot of information without words.", "japaneseMeaning": "物語る、多くを物語る", "etymology": "speak volumes（多くを語る）の比喩的表現。", "examples": {"B": "気候変動にグレーゾーンがあると思うこと自体が、科学を信じてないことを物語ってる。", "C": "アレックス、ローラに本気みたい。一緒にいるときのボディランゲージがすべてを物語ってる。", "D": "多くの情報を提供する。"}},
362: {"nativeDefinition": "To strongly emphasize something.", "japaneseMeaning": "〜を強調しすぎることはできない、いくら強調しても足りない", "etymology": "can't emphasize enough（十分に強調できない）の強調表現。", "examples": {"B": "英語が上手くなりたいなら、毎日英語に浸かる必要がある。いくら強調しても足りない。", "C": "毎日少しずつ改善することの大切さを、いくら強調しても足りない。それが成功につながる。", "D": "強く信じる。"}},
363: {"nativeDefinition": "Something that is absolutely unacceptable.", "japaneseMeaning": "大きなNG、絶対ダメ", "etymology": "big no-no（大きなノー）の口語表現。", "examples": {"B": "10時じゃなくて9時59分だよ。シフト終わる前に荷物まとめるのはここでは大きなNG。", "C": "許可なく他人の犬を撫でるのは大きなNGだと思う？", "D": "受け入れられない行動。"}},
364: {"nativeDefinition": "To have good intentions even if the result is bad.", "japaneseMeaning": "悪気はない、善意で", "etymology": "mean well（良い意味を持つ）の直訳的表現。", "examples": {"B": "母は時々傷つくことを言うけど、いつも悪気はない。", "C": "ロイにランチ誘われるのやめてほしい。悪気はないのはわかるけど、一人で食べたい。", "D": "善意を持っている。"}},
365: {"nativeDefinition": "Dangerous, risky, or frightening.", "japaneseMeaning": "危なっかしい、ヒヤヒヤする", "etymology": "hairy（毛深い）が「危険な」という口語的用法。", "examples": {"B": "飛行機の着陸はちょっとヒヤヒヤする。特に風が強いとき。", "C": "子供の頃、タランチュラでヒヤヒヤする経験した。だから彼女がペットにするの反対。", "D": "怖い。"}},
366: {"nativeDefinition": "To have no valid support for one's position.", "japaneseMeaning": "根拠がない、立場がない", "etymology": "have a leg to stand on（立つ脚がある）の否定形。", "examples": {"B": "クライアントは口頭で著作権譲渡に同意したと言うけど、契約に書いてないから根拠がない。", "C": "彼氏、テキスト履歴のスクショ全部あるなら根拠ないよ。浮気してるの明らか。", "D": "支持がない。"}},
367: {"nativeDefinition": "In a situation where no progress can be made.", "japaneseMeaning": "膠着状態、行き詰まり", "etymology": "stalemate（ステイルメイト）のチェス用語から。", "examples": {"B": "60分経ってもまだ膠着状態。", "C": "彼女と今夜誰が夕食作るか膠着してる。結局Uber Eats頼むことになりそう。", "D": "進展が不可能な状況。"}},
368: {"nativeDefinition": "Hurry up; drive faster.", "japaneseMeaning": "急いで、アクセル踏んで", "etymology": "step on it（それを踏む）の運転席からの口語。", "examples": {"B": "すみません、少し急いでもらえますか？遅れそうで。", "C": "バスが遅い。運転手さんアクセル踏んでほしい。トイレ行きたい。", "D": "急げ！"}},
369: {"nativeDefinition": "A hidden or secondary motive.", "japaneseMeaning": "裏の意図、隠れた動機", "etymology": "ulterior motive（奥の動機）の直訳的表現。", "examples": {"B": "急にカップケーキくれた。裏の意図が気になる。", "C": "中国が途上国を支援するのに裏の意図があると批判する人もいるけど、西側も同じだと思う。", "D": "隠れた理由。"}},
370: {"nativeDefinition": "A failure; something that did not succeed.", "japaneseMeaning": "失敗、ダメな結果", "etymology": "bust（破裂）が「失敗」というスラング用法。", "examples": {"B": "いくつかビジネスやってるから、一つ失敗しても大丈夫。", "C": "野球カード2パック買った。1パック目はダメだったけど、2パック目でショーheiオートグラフカード出た。かっこいい。", "D": "失敗。"}},
371: {"nativeDefinition": "To investigate or look around secretly.", "japaneseMeaning": "（こっそり）探り回る、詮索する", "etymology": "snoop around（こそこそ歩き回る）の口語表現。", "examples": {"B": "パートナーのスマホをこっそり覗くのはやめたほうがいい。いいことない。", "C": "好きな人のインスタをこっそり見てたら、いいねしそうになった。怖かった。", "D": "こっそり何かを探る。"}},
372: {"nativeDefinition": "In one's imagination or mental picture.", "japaneseMeaning": "心の中では、想像の中で", "etymology": "in one's mind's eye（心の目に）の直訳的表現。", "examples": {"B": "ピアノを弾くのは心の中ではかっこよさそうだったけど、上達にどれだけ練習が必要かわかってなかった。", "C": "会ったことないけど、心の中では完璧に姿が浮かぶ。", "D": "誰かの想像の中で。"}},
373: {"nativeDefinition": "To repair something temporarily.", "japaneseMeaning": "（何かを）応急処置する、つぎ合わせる", "etymology": "patch up（継ぎで直す）の直訳的表現。", "examples": {"B": "今、板挟み。車を応急処置に数千ドルかけるか、少し出して新しいの買うか。", "C": "医者に行ったほうがいい。あんな傷、応急処置じゃ無理。", "D": "一時的に修理する。"}},
374: {"nativeDefinition": "To make someone feel less guilty.", "japaneseMeaning": "（人の）良心を楽にする", "etymology": "ease one's conscience（良心を楽にする）の直訳的表現。", "examples": {"B": "海に落ちる一滴かもしれないけど、再利用カップで環境のためにできることをしたい。良心も楽になる。", "C": "チーズバーガー2つと大フライド食べたから、緑のジュース一杯で良心を楽にした。", "D": "誰かの罪悪感を和らげる。"}},
375: {"nativeDefinition": "In the modern era; nowadays.", "japaneseMeaning": "現代では、今の時代に", "etymology": "in this day and age（この日と時代に）の強調表現。", "examples": {"B": "政府はみんなに無料スマホを配るべき。現代ではスマホなしでは生きられない。", "C": "大臣がUSBが何かわからないって言って自分を笑いものにした。現代でそんなことある？", "D": "現在。"}},
376: {"nativeDefinition": "To leave; to head for the exit.", "japaneseMeaning": "退場する、辞める方向に向かう", "etymology": "head for the exit door（出口のドアに向かう）の直訳的表現。", "examples": {"B": "え、ロナウドが退場するの？チームにとって大きな損失だ。", "C": "ジャックが昼休みにLinkedInで求人見てた。退職の兆候かも。", "D": "去る。"}},
377: {"nativeDefinition": "A situation where one person's gain is another's loss.", "japaneseMeaning": "ゼロサムゲーム、一方が得すれば他方が損", "etymology": "zero-sum game（ゼロ和ゲーム）のゲーム理論用語。", "examples": {"B": "人生はゼロサムゲームじゃない。他人の成功を止めるな。", "C": "ビジネスはゼロサムゲームだと思う人もいるけど、俺はそう思わない。協力してウィンウィンを作れる。", "D": "一方の得が他方の損となるもの。"}},
378: {"nativeDefinition": "A mature person with old-fashioned values.", "japaneseMeaning": "老成した人、古風な魂", "etymology": "old soul（古い魂）の直訳的表現。", "examples": {"B": "物質主義じゃなく、シンプルな生活を好んで一人の時間を楽しむ。本当に老成した人だ。", "C": "テキストより電話が好き。俺はただの老成した人かも。", "D": "とても成熟した人、古風な人。"}},
379: {"nativeDefinition": "A collection of the best moments, not the full reality.", "japaneseMeaning": "ハイライトリール、良い部分だけの切り抜き", "etymology": "highlight reel（ハイライト映像）のSNS文脈での用法。", "examples": {"B": "みんなのインスタ見ると人生完璧に見えるけど、ハイライトリールに過ぎない。", "C": "俺のブログは食べ歩きのハイライトリール。いつも高級料理食べてるわけじゃない。", "D": "最高の部分。"}},
380: {"nativeDefinition": "To cause excitement, controversy, or commotion.", "japaneseMeaning": "騒ぎを起こす、波紋を広げる", "etymology": "cause a stir（かき混ぜる）の比喩的用法。", "examples": {"B": "バンクシーが140万ドルで売れた絵を破り捨てて騒ぎを起こした。", "C": "ホームレスの人へのコメントを聞いたとき、騒ぎになるとわかってた。", "D": "ドラマや騒動を作る。"}},
381: {"nativeDefinition": "To appear suddenly when something good happens.", "japaneseMeaning": "いきなり現れる、湧いてくる", "etymology": "come out of the woodwork（木材から出てくる）の慣用表現。", "examples": {"B": "何か新しいことを始めると、いきなり「本当にやるの？」って言う人が湧いてくる。気にしないで。", "C": "宝くじ当たった途端、女の子がいきなり湧いてきたの面白い。", "D": "突然現れる。"}},
382: {"nativeDefinition": "Both parties must be equally involved.", "japaneseMeaning": "二人でなければ成らない、双方の関与が必要", "etymology": "it takes two to tango（タンゴには二人必要）のことわざ。", "examples": {"B": "どんな関係も二人でなければ成らない。どれだけ愛してても、向こうも愛してくれないとダメ。", "C": "契約延長したいけど、二人でなければ成らない。交渉がうまくいくといいな。", "D": "双方が同等に関与する必要がある。"}},
383: {"nativeDefinition": "To promote or support something enthusiastically.", "japaneseMeaning": "（〜を）力強く推進する、太鼓を叩く", "etymology": "bang the drum（太鼓を叩く）の比喩的表現。", "examples": {"B": "在宅勤務を何年も推進してきた。もっと多くの人ができるようになって嬉しい。", "C": "この映画をずっと推してきた。おっと、彼から予告編のリンクが来た。", "D": "熱心に支持する。"}},
384: {"nativeDefinition": "To hold court; to be the center of attention.", "japaneseMeaning": "注目の的になる、話の中心にいる", "etymology": "hold court（宮廷を開く）の比喩的用法。", "examples": {"B": "あそこで注目の的になってる男、誰？有名人？", "C": "父がまた庭で話の中心になってる。みんな話に夢中になってるといいけど。", "D": "多くの注目を集めて楽しませる。"}},
385: {"nativeDefinition": "To have been better in the past.", "japaneseMeaning": "昔はもっと良かった、老朽化した", "etymology": "have seen better days（もっと良い日を見た）の慣用表現。", "examples": {"B": "日本経済は確かに昔はもっと良かったけど、他の国と比べればまだいい。", "C": "このジーンズ、もうボロボロ。新しいの買う時期かも。", "D": "以前はもっと良かった、劣化した。"}},
386: {"nativeDefinition": "Perfectly suited for someone or something.", "japaneseMeaning": "（〜に）ぴったりの、オーダーメイドの", "etymology": "tailor-made（仕立てられた）の直訳的表現。", "examples": {"B": "彼は背が高くて強い。バスケットボールのために生まれたみたい。", "C": "このスイミングクラスは初心者向けに作られてる。", "D": "何かに完璧に合っている。"}},
387: {"nativeDefinition": "To lose or come off worse in a competition.", "japaneseMeaning": "負ける、敗れる", "etymology": "come off second best（二番目に終わる）の慣用表現。", "examples": {"B": "また負けたけど、すごく接戦だった。前回はボコボコにされたから、確実に上達してる。", "C": "友達に煽られて食べチャレンジに参加したけど、残念ながら負けた。", "D": "敗れる。"}},
388: {"nativeDefinition": "To obstruct or interfere with someone.", "japaneseMeaning": "（人の）邪魔をする、妨げる", "etymology": "get in one's way（道に入る）の直訳的表現。", "examples": {"B": "妻が料理してるときはキッチンに入らないようにしてる。邪魔になるだけだから。", "C": "会議に付いてきていい？邪魔はしないから。", "D": "誰かを妨げる。"}},
389: {"nativeDefinition": "Including all flaws and imperfections.", "japaneseMeaning": "欠点も含めて、ありのままで", "etymology": "warts and all（イボも全部）の直訳的慣用表現。", "examples": {"B": "幸せになりたいなら、まず自分を欠点も含めて受け入れないと。", "C": "昨夜のデート、すごく意気投合した。欠点も含めて全部話し合った。", "D": "すべてのネガティブなものを含めて。"}},
390: {"nativeDefinition": "To act boldly without worrying about risks.", "japaneseMeaning": "思い切ってやる、慎重さを捨てる", "etymology": "throw caution to the wind（慎重さを風に投げる）の慣用表現。", "examples": {"B": "思い切って仕事辞めよう。毎日情熱のないことをするのはしっくりこない。", "C": "ソフトロブ初めて食べるけど、腕をひねられてるし、思い切って食べてみる。", "D": "大胆に行動する。"}},
391: {"nativeDefinition": "To prevent something from succeeding or progressing.", "japaneseMeaning": "（何かを）脱線させる、頓挫させる", "etymology": "derail（脱線させる）の比喩的用法。", "examples": {"B": "多くの政治家がレッドヘリングで会話を脱線させるのが本当に嫌い。", "C": "この電話で週末の計画が完全に脱線した。", "D": "何かの成功や進展を妨げる。"}},
392: {"nativeDefinition": "To be much better than someone at something.", "japaneseMeaning": "（人を）圧倒する、ずば抜けている", "etymology": "run circles around（周りを走り回る）の比喩。", "examples": {"B": "インテリアの面ではメルセデス・ベンツが他社を圧倒してる。", "C": "料理は父が喜んで全部やる。俺よりずば抜けてる。俺は皿洗い担当。", "D": "誰かより優れている。"}},
393: {"nativeDefinition": "To try something cautiously to see if it will work.", "japaneseMeaning": "様子を見る、試してみる", "etymology": "test the waters（水を試す）の比喩的表現。", "examples": {"B": "元カノと戻りたい？まずメッセージ送って様子見しよう。返事なければ次。", "C": "eBayに1200ドルで出品してみてる。様子見。そんな金払う人いないと思うけど。", "D": "成功の可能性を調べる。"}},
394: {"nativeDefinition": "To enjoy something greatly, often at someone's expense.", "japaneseMeaning": "（〜を）大いに楽しむ、ネタにする", "etymology": "have a field day（野外デーを過ごす）の比喩的用法。", "examples": {"B": "この男の仕草、すごく面白い。ジェフ・クリエイターが大いに楽しみそう。", "C": "大統領はすぐ誤字を修正したけど、SNSはもう大いに楽しんでる。", "D": "何かから大いに楽しむ。"}},
395: {"nativeDefinition": "Someone is not naive or easily fooled.", "japaneseMeaning": "（人は）バカじゃない、騙されない", "etymology": "wasn't born yesterday（昨日生まれたわけじゃない）の慣用表現。", "examples": {"B": "説明が辻褄合わない。日本に年利30%の貯蓄口座があるなんて信じると思った？バカじゃない。", "C": "おいおい、バカじゃないよ。犬が宿題食べたなんて信じるわけない。", "D": "誰かはそれほどバカじゃない。"}},
396: {"nativeDefinition": "Pretending to dislike something one cannot have.", "japaneseMeaning": "酸っぱいブドウ、負け惜しみ", "etymology": "イソップ童話『狐とブドウ』の酸っぱいブドウ（sour grapes）から。", "examples": {"B": "ネガティブなコメントに成功を奪われるな。ただの負け惜しみだ。", "C": "クリス、昇進しなくて「どうせ昇進したくなかった、責任多いし給料少ないし」って。負け惜しみでしょ？", "D": "嫉妬。"}},
397: {"nativeDefinition": "Requiring a lot of attention and effort.", "japaneseMeaning": "手のかかる、わがままな", "etymology": "high-maintenance（メンテナンスが多い）の直訳的表現。", "examples": {"B": "価格競争すべきじゃない。高価格は手のかかる顧客を引きつける。", "C": "彼女は手がかかって満足させにくいから、追うのやめた。", "D": "要求が多い。"}},
398: {"nativeDefinition": "If you don't see something, you forget about it.", "japaneseMeaning": "去る者は日々に疎し、眼の外なら心の外", "etymology": "out of sight, out of mind（見えなければ心にもない）のことわざ。", "examples": {"B": "うざい人はブロックする。眼の外なら心の外。", "C": "在宅勤務は大抵いいけど、昇進が難しくなる。眼の外なら心の外だから。", "D": "見えなければ無視しやすい。"}},
399: {"nativeDefinition": "To be a common characteristic in a family through genetics.", "japaneseMeaning": "家系に受け継がれる、血のせい", "etymology": "run in the family（家系で走る）の慣用表現。", "examples": {"B": "子供たちも背が高いね。家系に受け継がれてるみたい。", "C": "考えてみたら、父も祖父も声が低かった。たぶん家系に受け継がれてる。", "D": "遺伝的なものである。"}},
400: {"nativeDefinition": "To bully or repeatedly criticize someone unfairly.", "japaneseMeaning": "（人を）いじめる、当たり散らす", "etymology": "pick on（選んで当たる）で、弱い者いじめの意味。", "examples": {"B": "先生が聞いてないのにわかる質問ばかり当てる。いじめてる。", "C": "ジョンはただの冗談だって言うけど、明らかにエマをいじめてる。", "D": "誰かをいじめの標的にする。"}},
}
